fn vals_for(o: &Arg) -> String {
    debug!("vals_for: o={}", o.get_id());

    if let Some(vals) = utils::possible_values(o) {
        format!(
            "$(compgen -W \"{}\" -- \"${{cur}}\")",
            vals.iter()
                .filter(|pv| !pv.is_hide_set())
                .map(|n| n.get_name())
                .collect::<Vec<_>>()
                .join(" ")
        )
    } else if o.get_value_hint() == ValueHint::DirPath {
        String::from("") // should be empty to avoid duplicate candidates
    } else if o.get_value_hint() == ValueHint::Other {
        String::from("\"${cur}\"")
    } else {
        String::from("$(compgen -f \"${cur}\")")
    }
}

pub fn set_is_known_script(&self, specifier: &Url, is_script: bool) {
  let new_value = if is_script {
    ResolutionMode::Require
  } else {
    ResolutionMode::Import
  };
  // block to really ensure dashmap is not borrowed while trying to insert
  {
    if let Some(value) = self.known.get(specifier) {
      // you shouldn't be insert a value in here that's
      // already known and is a different value than what
      // was previously determined
      debug_assert_eq!(*value, new_value);
      return;
    }
  }
  self.known.insert(specifier.clone(), new_value);
}

fn start_skips_when_pid_not_visible() {
  // pick a PID that is unlikely to be in use and was never observed by
  // this process — start by spawning a child, capturing its PID, then
  // waiting for it to fully exit so the PID is no longer active.
  let mut child = Command::new(if cfg!(windows) { "cmd.exe" } else { "cat" })
    .stdin(Stdio::piped())
    .stdout(Stdio::null())
    .stderr(Stdio::null())
    .spawn()
    .unwrap();
  let pid = child.id();
  child.kill().unwrap();
  child.wait().unwrap();
  assert!(!is_process_active(pid));

  // start() should return false rather than spawning a thread that
  // would immediately exit() the test process.
  assert!(!start(pid));
}

fn make_many_named_pipes_parallel() {
  let mut handles = vec![];
  let barrier = Arc::new(Barrier::new(50));
  for _ in 0..50 {
    let barrier = barrier.clone();
    handles.push(std::thread::spawn(move || {
      barrier.wait();
      let (server, client) = create_named_pipe().unwrap();
      // SAFETY: For testing
      let server = unsafe { File::from_raw_handle(server) };
      // SAFETY: For testing
      let client = unsafe { File::from_raw_handle(client) };
      std::thread::sleep(std::time::Duration::from_millis(100));
      drop((server, client));
    }));
  }
  for handle in handles.drain(..) {
    handle.join().unwrap();
  }
}

fn get_test_url(test_dir: &Path, test: &str) -> Result<Url, anyhow::Error> {
  let mut path = None;
  for extension in ["ts", "js", "nocompile"] {
    let test_path = test_dir.join(format!("{test}.{extension}"));
    if test_path.exists() {
      path = Some(test_path);
      break;
    }
  }
  let Some(path) = path else {
    bail!("Test file not found");
  };
  let path = path.canonicalize()?.to_owned();
  let url = Url::from_file_path(path).unwrap().to_string();
  let base_url = Url::from_file_path(Path::new(env!("CARGO_MANIFEST_DIR")))
    .unwrap()
    .to_string();
  let url = Url::parse(&format!("test://{}", &url[base_url.len()..]))?;
  Ok(url)
}

pub fn op_ffi_read_i64(
  state: &mut OpState,
  ptr: *mut c_void,
  // Note: The representation of 64-bit integers is function-wide. We cannot
  // choose to take this parameter as a number while returning a bigint.
  #[bigint] offset: isize,
) -> Result<i64, ReprError> {
  let permissions = state.borrow_mut::<PermissionsContainer>();
  permissions.check_ffi_partial_no_path()?;

  if ptr.is_null() {
    return Err(ReprError::InvalidI64);
  }

  let value =
  // SAFETY: ptr and offset are user provided.
    unsafe { ptr::read_unaligned::<i64>(ptr.offset(offset) as *const i64) };
  // SAFETY: Length and alignment of out slice were asserted to be correct.
  Ok(value)
}

