fn run_cmd(&self, mut cmd: Command) -> Result<String, Error> {
    cmd.stdout(Stdio::piped());
    let mut child = cmd
        .spawn()
        .map_err(|e| format!("failed to spawn `op`: {}", e))?;
    let mut buffer = String::new();
    child
        .stdout
        .as_mut()
        .unwrap()
        .read_to_string(&mut buffer)
        .map_err(|e| format!("failed to read `op` output: {}", e))?;
    let status = child
        .wait()
        .map_err(|e| format!("failed to wait for `op`: {}", e))?;
    if !status.success() {
        return Err(format!("`op` command exit error: {}", status).into());
    }
    Ok(buffer)
}

pub fn set_color_choice(&mut self, color: Option<&str>) -> CargoResult<()> {
    if let ShellOut::Stream {
        stdout,
        stderr,
        color_choice,
        ..
    } = &mut self.output
    {
        let cfg = color
            .map(|c| c.parse())
            .transpose()?
            .unwrap_or(ColorChoice::CargoAuto);
        *color_choice = cfg;
        let stdout_choice = cfg.to_anstream_color_choice();
        let stderr_choice = cfg.to_anstream_color_choice();
        *stdout = AutoStream::new(std::io::stdout(), stdout_choice);
        *stderr = AutoStream::new(std::io::stderr(), stderr_choice);
    }
    Ok(())
}

fn print_string(&mut self, string: &str) {
    // Write the pending indent. A more concise way of doing this would be:
    //
    //   write!(self.out, "{: >n$}", "", n = self.pending_indentation as usize)?;
    //
    // But that is significantly slower. This code is sufficiently hot, and indents can get
    // sufficiently large, that the difference is significant on some workloads.
    self.out.reserve(self.pending_indentation as usize);
    self.out.extend(iter::repeat(' ').take(self.pending_indentation as usize));
    self.pending_indentation = 0;

    self.out.push_str(string);
    self.space -= string.len() as isize;
}

fn get_or<E>(&self, k: K, vacant: impl FnOnce() -> Result<V, E>) -> Result<&V, E> {
    // We cannot hold borrow_mut while calling `vacant`, since that might have to do lookups in this very map.
    if let Some(v) = self.0.borrow().get(&k) {
        let val: *const V = &**v;
        // This is safe because `val` points into a `Box`, that we know will not move and
        // will also not be dropped as long as the shared reference `self` is live.
        return unsafe { Ok(&*val) };
    }
    let new_val = Box::new(vacant()?);
    let val: *const V = &**self.0.borrow_mut().try_insert(k, new_val).ok().unwrap();
    // This is safe because `val` points into a `Box`, that we know will not move and
    // will also not be dropped as long as the shared reference `self` is live.
    unsafe { Ok(&*val) }
}

fn run_pass(&self, tcx: TyCtxt<'tcx>, body: &mut Body<'tcx>) {
    // Skip trivially aligned place types.
    let excluded_pointees = [tcx.types.bool, tcx.types.i8, tcx.types.u8];

    // When checking the alignment of references to field projections (`&(*ptr).a`),
    // we need to make sure that the reference is aligned according to the field type
    // and not to the pointer type.
    check_pointers(
        tcx,
        body,
        &excluded_pointees,
        insert_alignment_check,
        BorrowedFieldProjectionMode::FollowProjections,
    );
}

fn from_span_etc(
    span: Span,
    is_primary: bool,
    label: Option<String>,
    suggestion: Option<(&String, Applicability)>,
    je: &JsonEmitter,
) -> DiagnosticSpan {
    // obtain the full backtrace from the `macro_backtrace`
    // helper; in some ways, it'd be better to expand the
    // backtrace ourselves, but the `macro_backtrace` helper makes
    // some decision, such as dropping some frames, and I don't
    // want to duplicate that logic here.
    let backtrace = span.macro_backtrace();
    DiagnosticSpan::from_span_full(span, is_primary, label, suggestion, backtrace, je)
}

pub fn insert(&mut self, key: K) -> UniIndex {
    // We want an unused index. First we attempt to find one from `deassigned`,
    // and if `deassigned` is empty we generate a fresh index.
    let idx = self.deassigned.pop().unwrap_or_else(|| {
        // `deassigned` is empty, so all keys in use are already in `mapping`.
        // The next available key is `mapping.len()`.
        self.mapping.len().try_into().expect("UniMap ran out of useable keys")
    });
    if self.mapping.insert(key, idx).is_some() {
        panic!(
            "This key is already assigned to a different index; either use `get_or_insert` instead if you care about this data, or first call `remove` to undo the preexisting assignment."
        );
    };
    UniIndex { idx }
}

pub(crate) fn format_missing(&mut self, end: BytePos) {
    // HACK(topecongiro): we use `format_missing()` to extract a missing comment between
    // a macro (or similar) and a trailing semicolon. Here we just try to avoid calling
    // `format_missing_inner` in the common case where there is no such comment.
    // This is a hack, ideally we should fix a possible bug in `format_missing_inner`
    // or refactor `visit_mac` and `rewrite_macro`, but this should suffice to fix the
    // issue (#2727).
    let missing_snippet = self.snippet(mk_sp(self.last_pos, end));
    if missing_snippet.trim() == ";" {
        self.push_str(";");
        self.last_pos = end;
        return;
    }
    self.format_missing_inner(end, |this, last_snippet, _| this.push_str(last_snippet))
}

fn get_suggestion_text(&self) -> &'static str {
    match &self.func {
        IterFunctionKind::IntoIter(_) => {
            "use the original Iterator instead of collecting it and then producing a new one"
        },
        IterFunctionKind::Len => {
            "take the original Iterator's count instead of collecting it and finding the length"
        },
        IterFunctionKind::IsEmpty => {
            "check if the original Iterator has anything instead of collecting it and seeing if it's empty"
        },
        IterFunctionKind::Contains(_) => {
            "check if the original Iterator contains an element instead of collecting then checking"
        },
    }
}

pub unsafe fn unsafe_update_eq<T>(old_pointer: *mut T, new_value: T) -> bool
where
    T: PartialEq,
{
    // SAFETY: Caller obligation
    let old_ref: &mut T = unsafe { &mut *old_pointer };

    if *old_ref != new_value {
        *old_ref = new_value;
        true
    } else {
        // Subtle but important: Eq impls can be buggy or define equality
        // in surprising ways. If it says that the value has not changed,
        // we do not modify the existing value, and thus do not have to
        // update the revision, as downstream code will not see the new value.
        false
    }
}

